const raw = $input.first().json.content[0].text;
let report;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  report = match ? JSON.parse(match[0]) : {};
} catch(e) {
  report = { total_pendientes: 0, salud_pipeline: 'regular', score_operativo: 50, resumen_ejecutivo: 'Error al generar reporte', acciones_prioritarias: ['Revisar pipeline manualmente'], alerta_principal: 'Error en sistema de monitoreo' };
}

return [{ json: { ...report, generated_at: new Date().toISOString() } }];

