={{ JSON.stringify({
  chat_id: '8789162933',
  text: (() => {
    const r = $json;
    const saludIcon = {'buena':'✅','regular':'⚠️','critica':'🚨'}[r.salud_pipeline] || '❓';
    let msg = '📊 <b>Reporte de Calidad — HolaTacna</b>\n';
    msg += new Date().toLocaleString(\'es-CL\') + '\n\n';
    msg += saludIcon + ' <b>Salud del pipeline:</b> ' + (r.salud_pipeline || '').toUpperCase() + '\n';
    msg += '📈 <b>Score operativo:</b> ' + (r.score_operativo || 0) + '/100\n';
    msg += '📋 <b>Leads pendientes:</b> ' + (r.total_pendientes || 0) + '\n\n';
    if (r.alerta_principal) msg += '🚨 <b>ALERTA:</b> ' + r.alerta_principal + '\n\n';
    if (r.criticos && r.criticos.length > 0) {
      msg += '🔴 <b>Críticos (' + r.criticos.length + '):</b>\n';
      r.criticos.slice(0,3).forEach(c => { msg += '  • ' + c.nombre + ' — ' + c.servicio + ' (' + c.horas_espera + 'h sin contacto)\n'; });
      msg += '\n';
    }
    if (r.acciones_prioritarias && r.acciones_prioritarias.length > 0) {
      msg += '✅ <b>Acciones ahora:</b>\n';
      r.acciones_prioritarias.slice(0,3).forEach((a, i) => { msg += (i+1) + '. ' + a + '\n'; });
      msg += '\n';
    }
    msg += '💬 ' + (r.resumen_ejecutivo || '');
    return msg;
  })(),
  parse_mode: 'HTML'
}) }}

